from fastapi import APIRouter, Depends, BackgroundTasks
from sqlalchemy.orm import Session
from typing import List, Dict, Any
from app.core.database import get_db
from app.models.platform_listing import Platform
from app.services.sync_service import SyncService

router = APIRouter(prefix="/sync", tags=["sync"])


@router.post("/import/{platform}")
async def import_from_platform(
    platform: Platform,
    background_tasks: BackgroundTasks,
    db: Session = Depends(get_db)
):
    """Import existing listings from a platform"""
    sync_service = SyncService(db)

    try:
        products = await sync_service.import_from_platform(platform)

        # Cleanup browsers in background
        background_tasks.add_task(sync_service.cleanup)

        return {
            "message": f"Successfully imported {len(products)} products from {platform.value}",
            "count": len(products),
            "product_ids": [p.id for p in products]
        }
    except Exception as e:
        await sync_service.cleanup()
        return {"error": str(e)}


@router.post("/check-sold")
async def check_sold_items(
    background_tasks: BackgroundTasks,
    db: Session = Depends(get_db)
):
    """Check all platforms for sold items and sync status"""
    sync_service = SyncService(db)

    try:
        sold_items = await sync_service.check_for_sold_items()

        # Cleanup browsers in background
        background_tasks.add_task(sync_service.cleanup)

        return {
            "message": f"Found {len(sold_items)} sold items",
            "sold_items": sold_items
        }
    except Exception as e:
        await sync_service.cleanup()
        return {"error": str(e)}


@router.post("/all")
async def sync_all_products(
    background_tasks: BackgroundTasks,
    db: Session = Depends(get_db)
):
    """Sync all products that need syncing"""
    sync_service = SyncService(db)

    try:
        await sync_service.sync_all_products()

        # Cleanup browsers in background
        background_tasks.add_task(sync_service.cleanup)

        return {"message": "All products synced successfully"}
    except Exception as e:
        await sync_service.cleanup()
        return {"error": str(e)}


@router.get("/stats")
def get_sync_stats(db: Session = Depends(get_db)):
    """Get synchronization statistics"""
    from app.models.platform_listing import PlatformListing

    total_listings = db.query(PlatformListing).count()
    needs_sync = db.query(PlatformListing).filter(PlatformListing.needs_sync == True).count()
    has_errors = db.query(PlatformListing).filter(PlatformListing.sync_error != None).count()

    # Platform breakdown
    from sqlalchemy import func
    platform_counts = db.query(
        PlatformListing.platform,
        func.count(PlatformListing.id)
    ).group_by(PlatformListing.platform).all()

    return {
        "total_listings": total_listings,
        "needs_sync": needs_sync,
        "has_errors": has_errors,
        "by_platform": {platform.value: count for platform, count in platform_counts}
    }

import httpx
from typing import List, Dict, Optional, Any
from datetime import datetime
from app.integrations.base import BasePlatformIntegration
from app.core.config import settings


class MarktplaatsIntegration(BasePlatformIntegration):
    """Marktplaats official API integration"""

    def __init__(self):
        super().__init__()
        self.client_id = settings.MARKTPLAATS_CLIENT_ID
        self.client_secret = settings.MARKTPLAATS_CLIENT_SECRET
        self.redirect_uri = settings.MARKTPLAATS_REDIRECT_URI
        self.base_url = settings.MARKTPLAATS_API_BASE_URL
        self.access_token = None
        self.refresh_token = None

    async def authenticate(self) -> bool:
        """Authenticate using OAuth2"""
        # This will be called after the OAuth2 callback
        # Token exchange happens in the API endpoint
        return self.access_token is not None

    def set_tokens(self, access_token: str, refresh_token: str = None):
        """Set OAuth tokens (called after OAuth2 flow)"""
        self.access_token = access_token
        self.refresh_token = refresh_token

    async def _make_request(self, method: str, endpoint: str, **kwargs) -> Dict[str, Any]:
        """Make authenticated request to Marktplaats API"""
        if not self.access_token:
            raise Exception("Not authenticated. Please complete OAuth2 flow first.")

        headers = kwargs.pop("headers", {})
        headers["Authorization"] = f"Bearer {self.access_token}"

        async with httpx.AsyncClient() as client:
            response = await client.request(
                method,
                f"{self.base_url}{endpoint}",
                headers=headers,
                **kwargs
            )
            response.raise_for_status()
            return response.json()

    async def get_listings(self) -> List[Dict[str, Any]]:
        """Get all active listings"""
        try:
            data = await self._make_request("GET", "/advertisements")
            return data.get("advertisements", [])
        except Exception as e:
            print(f"Error fetching Marktplaats listings: {e}")
            return []

    async def create_listing(self, product_data: Dict[str, Any]) -> Optional[str]:
        """Create a new listing on Marktplaats"""
        try:
            # Transform product data to Marktplaats format
            listing_data = {
                "title": product_data["title"],
                "description": product_data["description"],
                "price": {
                    "amount": int(product_data["price"] * 100),  # Convert to cents
                    "currency": "EUR"
                },
                "categoryId": product_data.get("category", ""),
                "attributes": self._build_attributes(product_data),
                "images": product_data.get("images", [])
            }

            response = await self._make_request("POST", "/advertisements", json=listing_data)
            return response.get("id")
        except Exception as e:
            print(f"Error creating Marktplaats listing: {e}")
            return None

    async def update_listing(self, listing_id: str, product_data: Dict[str, Any]) -> bool:
        """Update an existing listing"""
        try:
            listing_data = {
                "title": product_data["title"],
                "description": product_data["description"],
                "price": {
                    "amount": int(product_data["price"] * 100),
                    "currency": "EUR"
                }
            }

            await self._make_request("PUT", f"/advertisements/{listing_id}", json=listing_data)
            return True
        except Exception as e:
            print(f"Error updating Marktplaats listing: {e}")
            return False

    async def delete_listing(self, listing_id: str) -> bool:
        """Delete a listing"""
        try:
            await self._make_request("DELETE", f"/advertisements/{listing_id}")
            return True
        except Exception as e:
            print(f"Error deleting Marktplaats listing: {e}")
            return False

    async def mark_as_sold(self, listing_id: str) -> bool:
        """Mark listing as sold"""
        try:
            await self._make_request("POST", f"/advertisements/{listing_id}/sold")
            return True
        except Exception as e:
            print(f"Error marking Marktplaats listing as sold: {e}")
            return False

    async def get_sales(self, since: Optional[datetime] = None) -> List[Dict[str, Any]]:
        """Get sales information"""
        try:
            params = {}
            if since:
                params["since"] = since.isoformat()

            data = await self._make_request("GET", "/sales", params=params)
            return data.get("sales", [])
        except Exception as e:
            print(f"Error fetching Marktplaats sales: {e}")
            return []

    async def check_listing_status(self, listing_id: str) -> Optional[str]:
        """Check listing status"""
        try:
            data = await self._make_request("GET", f"/advertisements/{listing_id}")
            return data.get("status")
        except Exception as e:
            print(f"Error checking Marktplaats listing status: {e}")
            return None

    def _build_attributes(self, product_data: Dict[str, Any]) -> Dict[str, Any]:
        """Build platform-specific attributes"""
        attributes = {}
        if product_data.get("size"):
            attributes["size"] = product_data["size"]
        if product_data.get("condition"):
            attributes["condition"] = product_data["condition"]
        if product_data.get("brand"):
            attributes["brand"] = product_data["brand"]
        if product_data.get("color"):
            attributes["color"] = product_data["color"]
        return attributes

    def get_oauth_url(self) -> str:
        """Get OAuth2 authorization URL"""
        return (
            f"{self.base_url}/oauth/authorize?"
            f"client_id={self.client_id}&"
            f"redirect_uri={self.redirect_uri}&"
            f"response_type=code&"
            f"scope=listings:read listings:write sales:read"
        )

from fastapi import APIRouter, Depends, HTTPException, BackgroundTasks
from sqlalchemy.orm import Session
from typing import List, Optional
import time
from app.core.database import get_db
from app.models.product import Product, ProductStatus
from app.models.platform_listing import Platform
from app.schemas.product import Product as ProductSchema, ProductCreate, ProductUpdate, ProductWithListings
from app.services.sync_service import SyncService
from app.utils.product_utils import generate_sku, calculate_investment

router = APIRouter(prefix="/products", tags=["products"])


@router.get("/", response_model=List[ProductSchema])
def get_products(
    skip: int = 0,
    limit: int = 100,
    status: Optional[ProductStatus] = None,
    db: Session = Depends(get_db)
):
    """Get all products"""
    query = db.query(Product)

    if status:
        query = query.filter(Product.status == status)

    products = query.offset(skip).limit(limit).all()
    return products


@router.get("/{product_id}", response_model=ProductWithListings)
def get_product(product_id: int, db: Session = Depends(get_db)):
    """Get a specific product with its platform listings"""
    product = db.query(Product).filter(Product.id == product_id).first()

    if not product:
        raise HTTPException(status_code=404, detail="Product not found")

    return product


@router.post("/", response_model=ProductSchema)
def create_product(product: ProductCreate, db: Session = Depends(get_db)):
    """Create a new product"""
    # Convert product to dict and remove investment_calculation field
    product_data = product.dict(exclude={"investment_calculation"})

    # Generate unique SKU
    sku = generate_sku(product.title, product.category)

    # Ensure SKU is unique
    while db.query(Product).filter(Product.sku == sku).first():
        sku = generate_sku(product.title + str(time.time()), product.category)

    product_data["sku"] = sku

    # Calculate investment if expression provided
    if product.investment_calculation:
        try:
            product_data["investment_per_product"] = calculate_investment(product.investment_calculation)
        except ValueError as e:
            raise HTTPException(status_code=400, detail=str(e))

    db_product = Product(**product_data)
    db.add(db_product)
    db.commit()
    db.refresh(db_product)
    return db_product


@router.put("/{product_id}", response_model=ProductSchema)
def update_product(
    product_id: int,
    product_update: ProductUpdate,
    db: Session = Depends(get_db)
):
    """Update a product"""
    db_product = db.query(Product).filter(Product.id == product_id).first()

    if not db_product:
        raise HTTPException(status_code=404, detail="Product not found")

    # Get update data and exclude investment_calculation field
    update_data = product_update.dict(exclude_unset=True, exclude={"investment_calculation"})

    # Calculate investment if expression provided
    if product_update.investment_calculation is not None:
        try:
            update_data["investment_per_product"] = calculate_investment(product_update.investment_calculation)
        except ValueError as e:
            raise HTTPException(status_code=400, detail=str(e))

    # Update fields
    for field, value in update_data.items():
        setattr(db_product, field, value)

    # Mark all platform listings as needing sync
    for listing in db_product.platform_listings:
        listing.needs_sync = True

    db.commit()
    db.refresh(db_product)
    return db_product


@router.delete("/{product_id}")
def delete_product(product_id: int, db: Session = Depends(get_db)):
    """Delete a product"""
    db_product = db.query(Product).filter(Product.id == product_id).first()

    if not db_product:
        raise HTTPException(status_code=404, detail="Product not found")

    db.delete(db_product)
    db.commit()
    return {"message": "Product deleted successfully"}


@router.post("/{product_id}/cross-post")
async def cross_post_product(
    product_id: int,
    platforms: List[Platform],
    background_tasks: BackgroundTasks,
    db: Session = Depends(get_db)
):
    """Cross-post a product to multiple platforms"""
    product = db.query(Product).filter(Product.id == product_id).first()

    if not product:
        raise HTTPException(status_code=404, detail="Product not found")

    sync_service = SyncService(db)

    try:
        results = await sync_service.cross_post_product(product, platforms)

        # Cleanup browsers in background
        background_tasks.add_task(sync_service.cleanup)

        return {
            "product_id": product_id,
            "results": {
                platform.value: {
                    "success": listing is not None,
                    "listing_id": listing.platform_listing_id if listing else None
                }
                for platform, listing in results.items()
            }
        }
    except Exception as e:
        await sync_service.cleanup()
        raise HTTPException(status_code=500, detail=str(e))


@router.post("/{product_id}/sync/{platform}")
async def sync_product_to_platform(
    product_id: int,
    platform: Platform,
    background_tasks: BackgroundTasks,
    db: Session = Depends(get_db)
):
    """Sync a product to a specific platform"""
    product = db.query(Product).filter(Product.id == product_id).first()

    if not product:
        raise HTTPException(status_code=404, detail="Product not found")

    sync_service = SyncService(db)

    try:
        listing = await sync_service.sync_product_to_platform(product, platform)

        # Cleanup browsers in background
        background_tasks.add_task(sync_service.cleanup)

        if listing:
            return {
                "success": True,
                "listing_id": listing.platform_listing_id,
                "platform": platform.value
            }
        else:
            raise HTTPException(status_code=500, detail="Failed to sync product")

    except Exception as e:
        await sync_service.cleanup()
        raise HTTPException(status_code=500, detail=str(e))


@router.post("/{product_id}/mark-sold")
async def mark_product_sold(
    product_id: int,
    platform: Platform,
    background_tasks: BackgroundTasks,
    sale_price: Optional[float] = None,
    db: Session = Depends(get_db)
):
    """Mark a product as sold on a specific platform"""
    product = db.query(Product).filter(Product.id == product_id).first()

    if not product:
        raise HTTPException(status_code=404, detail="Product not found")

    sync_service = SyncService(db)

    try:
        from datetime import datetime

        sale_data = {
            "sale_price": sale_price or product.price,
            "sale_date": datetime.now()
        }

        success = await sync_service.mark_product_as_sold(product_id, platform, sale_data)

        # Cleanup browsers in background
        background_tasks.add_task(sync_service.cleanup)

        if success:
            return {"message": "Product marked as sold successfully"}
        else:
            raise HTTPException(status_code=500, detail="Failed to mark product as sold")

    except Exception as e:
        await sync_service.cleanup()
        raise HTTPException(status_code=500, detail=str(e))

from fastapi import APIRouter, Depends, HTTPException
from sqlalchemy.orm import Session
from typing import List, Optional
from datetime import datetime, timedelta
from app.core.database import get_db
from app.models.sale import Sale
from app.models.platform_listing import Platform
from pydantic import BaseModel

router = APIRouter(prefix="/sales", tags=["sales"])


class SaleResponse(BaseModel):
    id: int
    product_id: int
    platform: str
    sale_price: float
    sale_date: datetime
    net_profit: Optional[float]
    synced_to_sheets: bool

    class Config:
        from_attributes = True


@router.get("/", response_model=List[SaleResponse])
def get_sales(
    skip: int = 0,
    limit: int = 100,
    platform: Optional[Platform] = None,
    days: Optional[int] = None,
    db: Session = Depends(get_db)
):
    """Get all sales with optional filters"""
    query = db.query(Sale)

    if platform:
        query = query.filter(Sale.platform == platform)

    if days:
        since_date = datetime.now() - timedelta(days=days)
        query = query.filter(Sale.sale_date >= since_date)

    sales = query.order_by(Sale.sale_date.desc()).offset(skip).limit(limit).all()
    return sales


@router.get("/stats")
def get_sales_stats(
    days: Optional[int] = 30,
    db: Session = Depends(get_db)
):
    """Get sales statistics"""
    from sqlalchemy import func

    # Base query
    query = db.query(Sale)

    if days:
        since_date = datetime.now() - timedelta(days=days)
        query = query.filter(Sale.sale_date >= since_date)

    # Total stats
    total_sales = query.count()
    total_revenue = db.query(func.sum(Sale.sale_price)).filter(
        Sale.sale_date >= (datetime.now() - timedelta(days=days)) if days else True
    ).scalar() or 0

    total_profit = db.query(func.sum(Sale.net_profit)).filter(
        Sale.sale_date >= (datetime.now() - timedelta(days=days)) if days else True
    ).scalar() or 0

    # Platform breakdown
    platform_sales = db.query(
        Sale.platform,
        func.count(Sale.id),
        func.sum(Sale.sale_price),
        func.sum(Sale.net_profit)
    ).filter(
        Sale.sale_date >= (datetime.now() - timedelta(days=days)) if days else True
    ).group_by(Sale.platform).all()

    platform_breakdown = {
        platform.value: {
            "count": count,
            "revenue": float(revenue or 0),
            "profit": float(profit or 0)
        }
        for platform, count, revenue, profit in platform_sales
    }

    return {
        "period_days": days,
        "total_sales": total_sales,
        "total_revenue": float(total_revenue),
        "total_profit": float(total_profit),
        "average_sale_price": float(total_revenue / total_sales) if total_sales > 0 else 0,
        "by_platform": platform_breakdown
    }


@router.get("/{sale_id}", response_model=SaleResponse)
def get_sale(sale_id: int, db: Session = Depends(get_db)):
    """Get a specific sale"""
    sale = db.query(Sale).filter(Sale.id == sale_id).first()

    if not sale:
        raise HTTPException(status_code=404, detail="Sale not found")

    return sale
